__uart_send_z:
__usendz_loop:
	LPM	R24, Z+
	TST	R24
	BREQ	__usendz_done
__usendz_wait:
	LDS	R25, 0x00C0
	SBRS	R25, 5
	RJMP	__usendz_wait
	STS	0x00C6, R24
	RJMP	__usendz_loop
__usendz_done:
	RET

